// ─────────────────────────────────────────────
// Prep T5 Fetch
// รับ param: ?tech=PAM (optional)
// Fetch ALL T5 ที่ Status ≠ เสร็จแล้ว
// กรอง date ใน N8N-side (Lark Date filter มีปัญหา 1254002)
// ─────────────────────────────────────────────
const token     = $input.first().json.tenant_access_token;
const qs        = $('GET /get-tech-jobs').first().json.query || {};
const techParam = (qs.tech || '').toUpperCase();

// Fetch ทุก T5 ที่ยังไม่ Done — ไม่ใส่ date filter (Lark Date filter พัง)
// ใส่ Status filter (SingleSelect ทำงานได้)
const searchBody = JSON.stringify({
  page_size: 500,
  filter: {
    conjunction: 'and',
    conditions: [{
      field_name: 'Status',
      operator:   'isNot',
      value:      ['เสร็จแล้ว']
    }]
  }
});

return [{ json: { lark_token: token, techParam, searchBody } }];

// ─────────────────────────────────────────────
// Parse & Filter Jobs
// กรอง: scheduled date = วันนี้ ± 1 วัน (BKK)
// คืน array of jobs สำหรับ tech.html
// ─────────────────────────────────────────────
function txt(v) {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.value !== undefined && Array.isArray(v.value)) {
    if (v.value.length === 0) return '';
    const f = v.value[0];
    if (typeof f === 'string') return f;
    if (f?.text) return f.text;
    if (f?.name) return f.name;
  }
  if (Array.isArray(v)) {
    if (v.length === 0) return '';
    const f = v[0];
    if (typeof f === 'string') return f;
    if (f?.text) return f.text;
    if (f?.name) return f.name;
  }
  if (v.text) return v.text;
  if (v.name) return v.name;
  return '';
}

const prep   = $('Prep T5 Fetch').first().json;
const tech   = prep.techParam || '';     // 'PAM' | '' (all)
const data   = $input.first().json;
const items  = data.data?.items || [];

// Bangkok date range: ยอมรับงานย้อนหลัง 1 วัน ถึงอนาคต 7 วัน
const BKK       = 7 * 3600 * 1000;
const nowMs     = Date.now();
const bkk       = new Date(nowMs + BKK);
const todayMs   = Date.UTC(bkk.getUTCFullYear(), bkk.getUTCMonth(), bkk.getUTCDate()) - BKK;
const rangeFrom = todayMs - 86400000;        // เมื่อวาน (งานค้างจากวาน)
const rangeTo   = todayMs + 7 * 86400000;   // ไป 7 วันข้างหน้า

const STATUS_LABELS = {
  'รอยืนยัน':          '⏳ รอยืนยัน',
  'ยืนยันแล้ว':         '✅ ยืนยันแล้ว',
  'กำลังดำเนินการ':     '🔧 กำลังดำเนินการ',
  'เสร็จแล้ว':          '✅ เสร็จแล้ว'
};

const jobs = items
  .map(item => {
    const f  = item.fields || {};
    const sd = parseInt(f['Scheduled Date']) || 0;
    return {
      record_id:    item.record_id,
      job_id:       txt(f['Job No.']),
      shop_name:    txt(f['Shop Name'])    || '(ไม่มีชื่อร้าน)',
      status:       txt(f['Status'])       || 'รอยืนยัน',
      status_label: STATUS_LABELS[txt(f['Status'])] || txt(f['Status']),
      scheduled_ms: sd,
      scheduled_date: sd ? new Date(sd + BKK).toISOString().substring(0, 10) : '',
      job_type:     Array.isArray(f['Job Type'])
                      ? f['Job Type'].join(', ')
                      : txt(f['Job Type']),
      stages:       Array.isArray(f['Stages Covered'])
                      ? f['Stages Covered'].join(', ')
                      : txt(f['Stages Covered']),
      maps_url:     txt(f['Google Maps URL'])  || '',
      line_id:      txt(f['C.LINE User ID'])   || ''
    };
  })
  .filter(job => {
    // กรองตาม date range
    if (job.scheduled_ms && (job.scheduled_ms < rangeFrom || job.scheduled_ms > rangeTo)) return false;
    return true;
  })
  .sort((a, b) => (a.scheduled_ms || 0) - (b.scheduled_ms || 0));

// Date display สำหรับ header
const TH_DAYS = ['อาทิตย์','จันทร์','อังคาร','พุธ','พฤหัส','ศุกร์','เสาร์'];
const dateLabel = 'วัน' + TH_DAYS[bkk.getUTCDay()] + ' ' + bkk.getUTCDate() + '/' + (bkk.getUTCMonth()+1);

return [{ json: { jobs, count: jobs.length, techFilter: tech, dateLabel } }];
